```python
from elasticsearch import Elasticsearch
import datetime
import json
import threading

# Устанавливаем подключение к Elasticsearch
es = Elasticsearch(
    ['http://10.0.9.39:9200'],
    use_ssl=False,
)

# Список хостов, данные по которым нужно получить
hosts = [
    "n757760", "n761209", "n764206", "n765244", "n767755", "n764265",
    "n766423", "n769860", "n768681", "n760260", "n766565", "n769177",
    "n766574", "n766522", "n766573", "n766538", "n763685", "n763854",
    "n764188", "n760134", "n764392", "n765768"
]

# Общая часть запроса
query_body = {
  "query": {
    "bool": {
      "must": [
        # Условие для hostname будет вставляться динамически для каждого хоста
      ]
    }
  },
  "sort": [
    {"@timestamp": "asc"}
  ]
}

# Базовое имя индекса
index_name = 'winlogbeat-2023.11.30'

# Функция для скроллинга
def scroll(es_obj, scroll_id, scroll_time = '1m', host_name='host'):
    while keep_running:    
        res = es_obj.scroll(scroll_id = scroll_id, scroll = scroll_time)
        scroll_id = res['_scroll_id']
        if len(res['hits']['hits']):
            # В текущем виде кода останавливается без сохранения последних данных,
            # Из-за этого здесь добавлено дополнительное условие на пустой список.
            yield res['hits']['hits']
        else:
            break

# Функция для остановки поиска по вводу с клавиатуры
def check_input():
    global keep_running
    input()  # Блокирующий вызов, ожидает ввода от пользователя
    keep_running = False

# Запуск потока для возможности прерывания выполнения
keep_running = True
threading.Thread(target=check_input).start()

# Основной цикл для каждого хоста
for host in hosts:
    # Устанавливаем фильтр по hostname
    query_body['query']['bool']['must'] = [
        {"term": {"beat.hostname": host}},
        {
          "range": {
            "@timestamp": {
              "gte": "now-50h"
            }
          }
        }
    ]

    # Подготавливаем запрос
    page = es.search(
      index=index_name,
      scroll='1h',
      size=1000,  # Увеличиваем размер батчей
      body=query_body
    )

    # Имя для сохранения файла
    file_name = f'{host}.json'

    with open(file_name, 'w') as f:
        for response in scroll(es, page['_scroll_id'], host_name=host):
            for hit in response:
                json_record = json.dumps(hit)
                f.write(json_record + '\n')

            # Прерываем если текущее время превышает установленный лимит
            if datetime.datetime.utcnow().time() >= datetime.time(18, 35, 59):
                break
